import React from 'react'
import { Row, Paragraph, Skeleton } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'
import useQualityScore from '../hooks/useQualityScore'
import ScoreTag from './ScoreTag'

type Props = {
  pid: string
  text?: string
}

export default function QualityScoreLabel({ pid, text }: Props): JSX.Element | null {
  const [t] = useTranslation()
  const { scoreFromProvider: scoreData, loadingFromProvider: loading } = useQualityScore({ pid })
  const personScore = scoreData?.visibility === 'PUBLIC' ? scoreData.personScores.overallDisplayScore : undefined

  const canShowTag = scoreData?.isValid
  const tagLabel = text || t('person-quality-score-issues.quality-score.label')

  if (canShowTag && loading) {
    return (
      <Row gutters="none">
        <div style={{ minWidth: 150 }}>
          <Skeleton.Paragraph size="sm" data-testid="loading-quality-score-chip" />
        </div>
        <Skeleton.Chip />
      </Row>
    )
  }

  if (canShowTag && !loading) {
    return (
      <Row guttersY="none" guttersX="xxs" alignY="middle" data-testid="quality-score-chip-loaded">
        <Paragraph size="sm">{tagLabel}</Paragraph>
        <ScoreTag score={personScore} />
      </Row>
    )
  }

  return null
}
