import { i18n } from '@fs/zion-locale'

export default function reducer(state, action) {
  let newState = {}
  switch (action.type) {
    case 'tooMany':
      newState = {
        hoverText: i18n.t(
          'unavailable.allowed-exceeded.hover-text',
          'You have exceeded the number of persons you are allowed to follow. To follow this person you will need to unfollow someone from the following list.'
        ),
        buttonText: i18n.t('unavailable', 'Unavailable'),
        disabled: true,
        isFollowing: false,
        followable: true,
      }
      break
    case 'transitionToUnfollow':
      newState = {
        hoverText: action.useActionWording ? i18n.t('unfollow', 'Unfollow') : i18n.t('following', 'Following'),
        buttonText: action.useActionWording ? i18n.t('unfollow', 'Unfollow') : i18n.t('following', 'Following'),
        disabled: true,
        isFollowing: true,
        followable: true,
      }
      break
    case 'transitionToFollow':
      newState = {
        hoverText: i18n.t('follow', 'Follow'),
        buttonText: i18n.t('follow', 'Follow'),
        disabled: true,
        isFollowing: false,
        followable: true,
      }
      break
    case 'following':
      newState = {
        hoverText: action.useActionWording
          ? i18n.t('unfollow.hover-text', 'To stop being notified of any changes to this person, click Unfollow.')
          : i18n.t(
              'following.hover-text',
              'To stop being notified of any changes to this person, click Following to unfollow.'
            ),
        buttonText: action.useActionWording ? i18n.t('unfollow', 'Unfollow') : i18n.t('following', 'Following'),
        isFollowing: true,
        followable: true,
      }
      if (action.pid) {
        document.body.dispatchEvent(new Event(`followed-${action.pid}`, { bubbles: true }))
      }
      break
    case 'notFollowing':
      newState = {
        hoverText: i18n.t('follow.hover-text', 'To be notified of any changes to this person, click Follow.'),
        buttonText: i18n.t('follow', 'Follow'),
        isFollowing: false,
        followable: true,
      }
      if (action.pid) {
        document.body.dispatchEvent(new CustomEvent(`unfollowed-${action.pid}`, { bubbles: true }))
      }
      break
    case 'notFollowable':
      newState = {
        isFollowing: false,
        followable: false,
      }
      break
    case 'unavailable':
    default:
      newState = {
        hoverText: i18n.t('unavailable', 'Unavailable'),
        buttonText: i18n.t('unavailable', 'Unavailable'),
        disabled: true,
        isFollowing: false,
        followable: false,
      }
  }

  return newState
}
