import { atTextDirection } from '@fs/zion-ui'

const viewBoxWidth = '34'
const viewBoxHeight = '32'

const getCommonIconVars = (isLarge) => ({
  // 45.34x43.34 gets the main icon to be 32x32 (small has the main icon at 24x24)
  width: isLarge ? '45.34' : '34',
  height: isLarge ? '43.34' : '32',
  viewBoxWidth,
  viewBoxHeight,
  mainTransformation: atTextDirection({ ltr: undefined, rtl: `scale(-1, 1) translate(-${viewBoxWidth}, 0)` }),
  letterTransformation: atTextDirection({ ltr: undefined, rtl: 'translate(10, 0)' }),
  timerTransformation: 'scale(0.7) translate(22, 0)',
})

export default getCommonIconVars
