import React from 'react'
import { useTranslation } from 'react-i18next'
import { OrdinancesStatus } from '@fs/zion-ordinances-status'
import { type PersonId } from '@fs/zion-tree-types'
import { type OrdinanceData } from './useTempleOrdinances'

type TempleOrdinancesProps = {
  /** The person id for linking to ordinances page */
  pid: PersonId | undefined
  /** Ordinance data to display */
  ordinances: OrdinanceData | undefined
  /** Whether the component is loading data */
  loading?: boolean
  /** Whether there was an error loading data */
  error?: boolean
}

/**
 * Temple ordinances display component.
 * This is a pure UI component that displays ordinance status.
 * Use the `useTempleOrdinances` hook to fetch data for this component.
 */
export default function TempleOrdinances({
  pid,
  ordinances,
  loading = false,
  error = false,
}: TempleOrdinancesProps): JSX.Element | null {
  const [t] = useTranslation()

  if (!error && !ordinances && !loading) return null

  if (error) return <span>{t('person.person-overlay.temple-ordinances.temple-information-unavailable')}</span>

  return (
    <OrdinancesStatus
      ordinances={ordinances}
      to={pid && pid !== 'UNKNOWN' ? `/tree/person/ordinances/${pid}/` : undefined}
      loading={loading}
      data-testid="temple-link"
    />
  )
}
