export const useLanguageTitle = (lang) => {
  return useMemo(() => {
    if (languageToScriptMap[lang]) {
      return i18n.t(scriptTranslationKeyMap[languageToScriptMap[lang]])
    }
    if (lang === 'und-Latn' || lang === 'x-Latn') {
      return i18n.t('name-template.ROMAN')
    }
    return lang
  }, [lang])
}

// Maps a language code to its translated template name.
export const getLanguageTemplateName = (lang, t) => {
  if (!lang) return ''

  const baseLang = lang.split('-')[0]

  const langToTranslationKey = {
    ar: 'name-template.arabic',
    bg: 'name-template.bulgarian',
    cs: 'name-template.czech',
    da: 'name-template.danish',
    de: 'name-template.german',
    el: 'name-template.GREEK',
    en: 'name-template.english',
    es: 'name-template.spanish',
    et: 'name-template.estonian',
    fa: 'name-template.farsi',
    fi: 'name-template.finnish',
    fr: 'name-template.french',
    hr: 'name-template.croatian',
    hu: 'name-template.hungarian',
    hy: 'name-template.ARMENIAN',
    id: 'name-template.indonesian',
    it: 'name-template.italian',
    ja: 'name-template.japanese',
    ka: 'name-template.georgian',
    km: 'name-template.KHMER',
    ko: 'name-template.korean',
    lt: 'name-template.lithuanian',
    lv: 'name-template.latvian',
    mg: 'name-template.malagasy',
    mn: 'name-template.MONGOLIAN',
    ms: 'name-template.malay',
    nl: 'name-template.dutch',
    no: 'name-template.norwegian',
    pl: 'name-template.polish',
    pt: 'name-template.portuguese',
    ro: 'name-template.romanian',
    ru: 'name-template.russian',
    sk: 'name-template.slovak',
    sm: 'name-template.samoan',
    sq: 'name-template.albanian',
    sv: 'name-template.swedish',
    sw: 'name-template.swahili',
    th: 'name-template.THAI',
    tl: 'name-template.tagalog',
    to: 'name-template.tongan',
    tr: 'name-template.turkish',
    uk: 'name-template.ukrainian',
    und: 'name-template.other',
    vi: 'name-template.VIETNAMESE',
    zh: 'name-template.chinese',
  }

  const translationKey = langToTranslationKey[baseLang]
  if (translationKey) {
    return t(translationKey)
  }

  return lang
}
