import React from 'react'
import PropTypes from 'prop-types'
import { css } from '@linaria/core'
import { DescriptionTooltip, Paragraph, Row, Skeleton, colors } from '@fs/zion-ui'
import { Link } from '@fs/zion-router'
import { VisuallyHidden } from '@reach/visually-hidden'
import { NoticeLoading } from '@fs/zion-icon'
import {
  BaptismSharedTemple,
  ConfirmationSharedTemple,
  InitiatorySharedTemple,
  EndowmentSharedTemple,
  SPSharedTemple,
  SSSharedTemple,
} from './shared-ready-icons'

// To match icons with svgs of 120day icons, we add extra width to the right
const EXTRA_WIDTH_LG = 13.34 // 32px (width of main icon) + 13.34px (width of clock icon) = 45.34px of total width of svg
const EXTRA_WIDTH_SM = 10 // 24px (width of main icon) + 10px (width of clock icon) = 34px of total width of svg

const templeCss = css`
  color: ${colors.gray00};
  width: 24px;
  height: 24px;
  display: inline-grid;
  justify-content: center;
  align-items: center;
  line-height: 0;
  margin-inline-end: ${EXTRA_WIDTH_SM}px;
  font-size: 14px;
  border-radius: 3px;

  &[status='Ready'],
  &[status='ReservedSharedReady'],
  &[status='NeedsPermission'] {
    color: ${colors.green80};
    border: 1.5px solid ${colors.green80};
    background: ${colors.green10};
    &:focus {
      background: ${colors.green30};
    }
  }

  &[status='NotAvailable'] {
    color: ${colors.gray90};
    background: none;
    border: 2px dashed ${colors.gray100};

    &:focus {
      background: ${colors.gray05};
      border: unset;
    }
  }

  &[status='NotNeeded'],
  &[status='Completed'] {
    color: ${colors.gray00};
    background: ${colors.gray30};
    &:focus {
      background: ${colors.gray50};
    }
  }

  &[status='Invalid'],
  &[status='NeedsMoreInformation'],
  &[status='NotApplicable'],
  &[status='NotReady'] {
    color: ${colors.yellow90};
    background: ${colors.yellow10};
    &:focus {
      background: ${colors.yellow30};
    }
  }

  &[status='InProgressPrinted'],
  &[status='InProgressNotPrinted'],
  &[status='InProgressWaiting'],
  &[status='SharedInProgressNotPrinted'],
  &[status='SharedInProgressPrinted'] {
    background: ${colors.blue60};
    &:focus {
      background: ${colors.blue90};
    }
  }
  &[status='Calculating'] {
    min-height: 4px;
    border-top: 4px solid #cccccc;
    padding-top: 4px;
  }
  &[icon-size='lg'] {
    // Matches width of svgs of 32px width of main icon and 45.34px of total width of icon
    margin-inline-end: ${EXTRA_WIDTH_LG}px;
    min-height: 32px;
    min-width: 32px;
  }

  &:visited,
  &:focus,
  &:hover {
    text-decoration: none;
  }
`
const statusCss = css`
  margin-inline-start: 18px;
`

const listItemCss = css`
  display: flex;
  text-overflow: ellipsis;
  align-items: center;
  /* Line height added to allow for multiple lines of text */
  line-height: normal;
  /* TW-3275: Removed white-space: nowrap so that long text in some languages (like MN) don't run into other elements to the right. */

  /* Apply border-radius for 120-day SVG, since it doesn't get wrapped with templeCss */
  & svg {
    border-radius: 3px;
    margin-bottom: 3px;
  }
`

const liCss = css`
  list-style: none;
  margin: 0;
  padding: 0;
`

const iconCss = css`
  &:not(&[icon-size='lg']) {
    margin: 8px 0;
  }
  &[icon-size='lg'] {
    margin-top: 11px;
  }
`

const getIcon = (type, isLarge) => {
  switch (type) {
    case 'B':
      return <BaptismSharedTemple isLarge={isLarge} />
    case 'C':
      return <ConfirmationSharedTemple isLarge={isLarge} />
    case 'I':
      return <InitiatorySharedTemple isLarge={isLarge} />
    case 'E':
      return <EndowmentSharedTemple isLarge={isLarge} />
    case 'SP':
      return <SPSharedTemple isLarge={isLarge} />
    case 'SS':
      return <SSSharedTemple isLarge={isLarge} />
    default:
      return console.error('Invalid type passed in')
  }
}

const shorthandMap = {
  baptism: 'B',
  confirmation: 'C',
  initiatory: 'I',
  endowment: 'E',
  sealingtoparents: 'SP',
  sealingtospouse: 'SS',
}

/**
 * A block whose color, outline, and title text indicate the status of a particular ordinance.
 * @param {boolean} [stacked=false] -    Whether the ordinance is stacked or horiziontal.
 * @param {boolean} [hoverText=false] -  To show hoverText instead of statusText for stacked mode.
 * @param {boolean} [templePage=false] - Being rendered on the temple page.
 * @param {object}  ordinance -          The ordinance object.
 * @param {string}  shorthand -          Which ordinance we are displaying information for. Valid options: "B"|"C"|"I"|"E"|"SP"|"SS"
 *                                       Will be calculated from ordinance.type if not provided.
 * @param {string}  [iconSize='sm'] -    Size of the icon
 * @param {string}  to -                 The href to link to.
 * @param {boolean} loading -  Loading indicator for loading states
 * @param {object}  otherProps -         The rest of the props passed.
 * @returns {HTMLElement} - The React element itself.
 */
export default function OrdinanceStatus({
  stacked = false,
  hoverText = false,
  templePage = false,
  ordinance,
  shorthand,
  iconSize = 'sm',
  to,
  loading,
  ...otherProps
}) {
  const noShow =
    !ordinance || (templePage && (ordinance.callerReservationDetails || ordinance.status === 'NotApplicable'))
  // On the temple page we don't render the ordinance box if status is NotApplicable or if callerReservationDetails object exists.
  // A callerReservationDetails object on an ordinance means that the patron no longer has the ordinance reserved, probably because of a merge.
  if (noShow) {
    return null
  }
  if (!shorthand && ordinance.type) {
    shorthand = shorthandMap[ordinance.type.replace(/[-_]/g, '').toLowerCase()]
  }

  const svgIcon = ordinance.status === 'ReservedSharedReady' && getIcon(shorthand, iconSize === 'lg')
  const El = to ? Link : 'div'
  const linkProps = to
    ? {
        to,
        external: true,
        noLinkStyles: true,
      }
    : {}

  if ((ordinance.status === 'Calculating' || loading) && stacked) {
    return (
      <Row gutters="xxs" alignY="middle" data-testid="ordinance-status-skeleton">
        <NoticeLoading size={iconSize} />
        <Skeleton.Paragraph growX maxWidth={200} size="xs" />
      </Row>
    )
  }

  if ((ordinance.status === 'Calculating' || loading) && !stacked) {
    const iconSizeInPixels = iconSize === 'lg' ? 32 : 24
    return (
      <div
        data-testid="ordinance-status-skeleton-not-stacked"
        style={{ margin: iconSize === 'lg' ? `11px ${EXTRA_WIDTH_LG}px 11px 0` : `8px ${EXTRA_WIDTH_SM}px 8px 0` }}
      >
        <Skeleton.Image height={iconSizeInPixels} width={iconSizeInPixels} />
      </div>
    )
  }

  return (
    <li className={liCss}>
      <VisuallyHidden> {ordinance.hoverText} </VisuallyHidden>
      <span aria-hidden>
        <DescriptionTooltip
          target={
            <div className={listItemCss}>
              {(svgIcon && <El {...linkProps}>{svgIcon}</El>) || (
                <div className={iconCss} icon-size={iconSize}>
                  <El
                    {...linkProps}
                    status={ordinance.status}
                    icon-size={iconSize}
                    data-testid={`ordinance-status:${shorthand}`}
                    temple-page={templePage.toString()}
                    aria-label={ordinance.statusText}
                    className={templeCss}
                    {...otherProps}
                  >
                    <span>{shorthand}</span>
                  </El>
                </div>
              )}
              {stacked && (
                <span className={statusCss}>
                  <Paragraph size="sm" as="span">
                    {hoverText ? ordinance.hoverText : ordinance.statusText}
                  </Paragraph>
                </span>
              )}
            </div>
          }
          label={ordinance.hoverText}
        />
      </span>
    </li>
  )
}

const statuses = [
  'Ready',
  'NeedsMoreInformation',
  'InProgressPrinted',
  'InProgressNotPrinted',
  'InProgressWaiting',
  'Completed',
  'NotAvailable',
  'NotNeeded',
  'Invalid',
  'NeedsPermission',
  'NotReady',
  'ReservedSharedReady',
  'SharedInProgressNotPrinted',
  'SharedInProgressPrinted',
  'NotApplicable',
  'Calculating',
  '',
]

OrdinanceStatus.propTypes = {
  /** The shorthand descriptor for the ordinance */
  shorthand: PropTypes.oneOf(['B', 'C', 'I', 'E', 'SP', 'SS']),
  /** Ordinance to render a status box for. `statusText` property required if using with the `stacked` prop */
  ordinance: PropTypes.shape({
    status: PropTypes.oneOf(statuses).isRequired,
    hoverText: PropTypes.string,
    statusText: PropTypes.string,
  }),
  /** Whether component is being rendered on the temple page */
  templePage: PropTypes.bool,
  /** Whether to stack ordinances vertically. (This will show ordinance status text to the side of each box) */
  stacked: PropTypes.bool,
  /** To show hoverText instead of statusText for stacked mode */
  hoverText: PropTypes.bool,
  /** size of the ordinance icons */
  iconSize: PropTypes.oneOf(['sm', 'lg']),
  /** Optional href to link to if clicked. */
  to: PropTypes.string,
  /** Loading indicator for loading states */
  loading: PropTypes.bool,
}

OrdinanceStatus.defaultProps = {
  templePage: false,
  stacked: false,
  hoverText: false,
  iconSize: 'sm',
}
