import React from 'react'
import PropTypes from 'prop-types'
import { css } from '@linaria/core'
import OrdinanceStatus from './OrdinanceStatus'

const cellStyle = css`
  font-size: 14px;
  display: grid;
  min-height: 25px;
  line-height: 0;
  grid-gap: 4px 2px;
  grid-auto-flow: column;
  justify-content: start;
  align-items: start;
  list-style-type: '';
  margin: 0;
  padding: 0;
  &[vertical='true'] {
    grid-template-columns: 1fr;
    grid-auto-flow: row;
  }
  &[icon-size='lg'] {
    grid-gap: 4px 8px;
  }
  & li {
    margin: 0;
    padding: 0;
  }
`

const defaultOrdinanceShape = {
  baptism: { status: '' },
  confirmation: { status: '' },
  initiatory: { status: '' },
  endowment: { status: '' },
  sealingToParents: { status: '' },
  sealingToSpouses: { status: '' },
}

/**
 * OrdinancesStatus accepts an ordinances object and displays the individual ordinances accordingly.
 * @param {object} ordinances - The ordinances to display.
 * @returns {HTMLElement} - JSX.
 */

/**
 * [OrdinancesStatus accepts an ordinances object and displays the individual ordinances accordingly.
 * @param   {object}  [ordinances=defaultOrdinanceShape] - The ordinances array.
 * @param   {boolean} [templePage=false] -                 If being rendered on the temple page.
 * @param   {boolean} [stacked=false] -                    If to render vertically or horizontally.
 * @param   {boolean} [hoverText=false] -                  To show hoverText instead of statusText for stacked mode.
 * @param   {string}  [iconSize='sm'] -                    Size of the icon.
 * @param   {string}  to -                                 Optional href to link to.
 * @param   {boolean}  loading -                 Loading indicator for loading states
 * @param   {object}  otherProps -                         The rest of the props
 * @returns {HTMLElement} - JSX.
 */
export default function OrdinancesStatus({
  ordinances,
  templePage = false,
  stacked = false,
  hoverText = false,
  iconSize = 'sm',
  to,
  loading,
  ...otherProps
}) {
  // If null is passed in, ordinances will be null instead of the defaultOrdinanceShape
  ordinances = ordinances ?? defaultOrdinanceShape
  /** We are doing this mapping so that OrdinanceStatus.js can work with the data
   *  the original munger in temple-r9 was not created to be shareable yet.
   */

  return (
    <ol vertical={stacked.toString()} icon-size={iconSize} className={cellStyle} {...otherProps}>
      <OrdinanceStatus
        iconSize={iconSize}
        shorthand="B"
        ordinance={ordinances.baptism}
        stacked={stacked}
        hoverText={hoverText}
        templePage={templePage}
        to={to}
        loading={loading}
      />
      <OrdinanceStatus
        iconSize={iconSize}
        shorthand="C"
        ordinance={ordinances.confirmation}
        stacked={stacked}
        hoverText={hoverText}
        templePage={templePage}
        to={to}
        loading={loading}
      />
      <OrdinanceStatus
        iconSize={iconSize}
        shorthand="I"
        ordinance={ordinances.initiatory}
        stacked={stacked}
        hoverText={hoverText}
        templePage={templePage}
        to={to}
        loading={loading}
      />
      <OrdinanceStatus
        iconSize={iconSize}
        shorthand="E"
        ordinance={ordinances.endowment}
        stacked={stacked}
        hoverText={hoverText}
        templePage={templePage}
        to={to}
        loading={loading}
      />
      <OrdinanceStatus
        iconSize={iconSize}
        shorthand="SP"
        ordinance={ordinances.sealingToParents}
        stacked={stacked}
        hoverText={hoverText}
        templePage={templePage}
        to={to}
        loading={loading}
      />
      <OrdinanceStatus
        iconSize={iconSize}
        shorthand="SS"
        ordinance={ordinances.sealingToSpouses || ordinances.sealingToSpouse}
        stacked={stacked}
        hoverText={hoverText}
        templePage={templePage}
        to={to}
        loading={loading}
      />
      {/** The ordinance prop is different ^^^ due to different calls to get data for component in personCard vs temple-r9. */}
    </ol>
  )
}

OrdinancesStatus.propTypes = {
  /** Object containing all ordinances to render a status box for. If using with `stacked` prop, ensure each ordinance has a `statusText` property. */
  ordinances: PropTypes.shape({
    baptism: PropTypes.object,
    confirmation: PropTypes.object,
    initiatory: PropTypes.object,
    endowment: PropTypes.object,
    sealingToParents: PropTypes.object,
    sealingToSpouses: PropTypes.object,
  }),
  /** Whether component is being rendered on the temple page */
  templePage: PropTypes.bool,
  /** Whether to stack ordinances vertically. (This will show ordinance status text to the side of each box) */
  stacked: PropTypes.bool,
  /** To show hoverText instead of statusText for stacked mode */
  hoverText: PropTypes.bool,
  /** size of the ordinance icons. */
  iconSize: PropTypes.oneOf(['sm', 'lg']),
  /** Optional href to link to if clicked. */
  to: PropTypes.string,
  /** Loading indicator for loading states */
  loading: PropTypes.bool,
}

OrdinancesStatus.defaultProps = {
  ordinances: defaultOrdinanceShape,
  templePage: false,
  stacked: false,
  hoverText: false,
  iconSize: 'sm',
}
