import axios from '@fs/zion-axios'
import Cache from '@fs/zion-cache'

// Briefly cached, mainly to prevent multiple duplicate calls made between shared components that each need the data
const cache = new Cache({ storeName: 'follow', lifetime: 3000 })

export async function getFollowStatus(pid) {
  const data = await cache.getItem(`follow-state-${pid}`)
  if (data) return { data }

  return axios.get(`/service/tree/tree-data/watch/${pid}/status`).then((res) => {
    cache.setItem(`follow-state-${pid}`, res.data)
    return res
  })
}

export function followPerson(pid) {
  return axios.put(`/service/tree/tree-data/watch/${pid}`).then((res) => {
    // If successful, update cache
    if (res.status === 201) {
      cache.setItem(`follow-state-${pid}`, { followable: true, following: true })
    }
    return res
  })
}

export function unfollowPerson(pid) {
  return axios.delete(`/service/tree/tree-data/watch/${pid}`).then((res) => {
    // If successful, update cache
    if (res.status === 204) {
      cache.setItem(`follow-state-${pid}`, { followable: true, following: false })
    }

    return res
  })
}
