import React from 'react'
import { Skeleton, DataBlock, Separator } from '@fs/zion-ui'
import { useUserProfile } from '@fs/zion-user'
import { useTranslation } from 'react-i18next'
import { VisuallyHidden } from '@reach/visually-hidden'

export default function AssociatedUser({ cisId, inOverlay }) {
  const { userProfileLoading, userProfile } = useUserProfile(cisId)
  const { t } = useTranslation()

  if (userProfileLoading) {
    return (
      <>
        {!inOverlay && <Skeleton.H5 width={200} />}
        {/* We don't want to announce if we're in PersonSheet or PersonOverlay. */}
        {inOverlay && <VisuallyHidden aria-live="assertive">{t('common-ui:loading.ellipsis.label')}</VisuallyHidden>}
        <Skeleton.Paragraph lineCount={2} size="sm" />
      </>
    )
  }
  return (
    <div>
      <Separator size="nano" />
      <DataBlock inline heading={t('person.associated-user.heading')} data={userProfile?.name?.value} />
      {/* We don't want to announce if we're in PersonSheet or PersonOverlay. */}
      {inOverlay && (
        <VisuallyHidden aria-live="assertive">
          {t('person.associated-user.body', { name: userProfile?.name?.value })}
        </VisuallyHidden>
      )}
      <Separator size="nano" />
    </div>
  )
}
