import { useZionAxios as useZionAxiosUntyped } from '@fs/zion-axios'
import { useShowTemple, useNonReligiousMode as useNonReligiousModeUntyped } from '@fs/zion-permissions'
import { type useNonReligiousMode as useNonReligiousModeTyped } from '@fs/zion-tree-types/zion-permissions'
import { type WrappedResponse, type PersonId } from '@fs/zion-tree-types'
import { type useZionAxios as useZionAxiosTyped } from '@fs/zion-tree-types/zion-axios'

const useNonReligiousMode = useNonReligiousModeUntyped as typeof useNonReligiousModeTyped
const useZionAxios = useZionAxiosUntyped as typeof useZionAxiosTyped

const transformResponse = (res: string): WrappedResponse<OrdinanceData>['data'] => {
  const response = JSON.parse(res)
  if (response.status !== 'OK') {
    throw new Error(`ordinance-error ${response.statuses?.[0]?.cause}`)
  }

  return response.data
}

export type OrdinanceStatus =
  | 'Ready'
  | 'NeedsMoreInformation'
  | 'InProgressPrinted'
  | 'InProgressNotPrinted'
  | 'InProgressWaiting'
  | 'Completed'
  | 'NotAvailable'
  | 'NotNeeded'
  | 'Invalid'
  | 'NeedsPermission'
  | 'NotReady'
  | 'SharedInProgressNotPrinted'
  | 'SharedInProgressPrinted'
  | 'NotApplicable'

export type Ordinance = {
  status?: OrdinanceStatus
  hoverText?: string
}

export type OrdinanceData = {
  id?: string
  baptism?: Ordinance
  confirmation?: Ordinance
  initiatory?: Ordinance
  endowment?: Ordinance
  sealingToParents?: Ordinance
  sealingToSpouses?: Ordinance
}

export function useTempleOrdinances(
  pid: PersonId | undefined
): ReturnType<typeof useZionAxios<WrappedResponse<OrdinanceData>['data']>>[0] {
  const [nonReligiousModeCheck, nonReligiousModeStatus, nonReligiousModeError] = useNonReligiousMode()
  const isNonReligiousModeActive =
    nonReligiousModeStatus === 'loading' || nonReligiousModeError !== null || nonReligiousModeCheck
  const [showTemple] = useShowTemple()
  const url =
    pid && pid !== 'UNKNOWN' && showTemple && !isNonReligiousModeActive
      ? `/service/tree/tree-data/reservations/person/${pid}/card?enforceTemplePolicyEx=true`
      : undefined
  const [{ data, error, loading }] = useZionAxios<WrappedResponse<OrdinanceData>['data']>({
    url,
    transformResponse,
  })

  return {
    data,
    loading,
    error,
  }
}
