import React, { memo, useRef, useContext, type MutableRefObject, type ComponentType } from 'react'
import { VisuallyHidden } from '@reach/visually-hidden'
import {
  Button,
  Row,
  Separator,
  Divider,
  Skeleton,
  Tag,
  Theme,
  colors,
  Paragraph,
  LayoutBand,
  Bleed,
} from '@fs/zion-ui'
import { Link } from '@fs/zion-router'
import {
  type SummaryPerson,
  type TdPerson,
  type Person as CardPerson,
  type VitalEventConclusion,
} from '@fs/zion-tree-types'
import RelationshipViewerButton, { RelationshipViewerContext } from '@fs/zion-relationship-viewer'
import Follow from '@fs/zion-follow'
import { QualityScoreLabel } from '@fs/zion-person-quality-score-issues'
import { useTranslation } from 'react-i18next'
import { Person as PersonIcon, TreePedigree } from '@fs/zion-icon'
import { Conclusion } from '@fs/zion-conclusion'
import { useAutoFocus } from '@fs/zion-ui/quarks-authorized-use-only'
import { usePermission } from '@fs/zion-permissions'
import { isLoadingPerson, isUnknownPerson, type LoadingPerson, type UnknownPerson } from '@fs/zion-person-service'
import AssociatedUser from '../AssociatedUser/AssociatedUser'
import TempleOrdinances from './components/TempleOrdinances'
import { useTempleOrdinances } from './components/useTempleOrdinances'
import Person from '../Person/Person'

const SideSheetDivider = (): JSX.Element => <Divider marginY="xs" />

const ConclusionSkel = (): JSX.Element => (
  <div>
    <Separator size="sm" />
    <Skeleton.H5 hasOverline />
    <Skeleton.H5 hasOverline />
  </div>
)

type BannerProps = { displayPerson: UnknownPerson | (SummaryPerson & Partial<TdPerson | CardPerson>) }

// Overlays have built-in padding, which we need to override to allow full-width display, so we inject our own element, here
const Banners = ({ displayPerson }: BannerProps): JSX.Element => {
  const [t] = useTranslation()
  return (
    <Bleed top>
      <Theme theme="complementary">
        {/* we are using complementary theming rather than the white text component */}
        <LayoutBand color={colors.gray02} data-testid="notice-banner-block">
          <Separator size="xxs" />
          {displayPerson.deleted && (
            <Paragraph data-testid="deleted-banner" size="sm">
              {t('person.person-overlay.deleted-notice')}
            </Paragraph>
          )}
          {isUnknownPerson(displayPerson) && (
            <Paragraph data-testid="unknown-banner" size="sm">
              {t('person.person-overlay.details-unavailable-message')}
            </Paragraph>
          )}
          <Separator size="xxs" />
        </LayoutBand>
      </Theme>
      <Separator size="xxs" />
    </Bleed>
  )
}

type SubheaderLinkProps = {
  Icon?: ComponentType
  text: string
  to: string
  onClick?: () => void
  external?: boolean
  linkName?: string
  target?: string
}

const SubheaderLink = ({ Icon, text, to, onClick, external, linkName, target }: SubheaderLinkProps): JSX.Element => {
  return (
    <>
      <Link
        to={to}
        onClick={onClick}
        linkName={linkName}
        external={external}
        target={target}
        wayfinding
        aria-label={text}
      >
        <span style={{ cursor: 'pointer' }}>
          <Row alignY="middle" gutters="nano">
            {Icon && <Icon />}
            {text}
          </Row>
        </span>
      </Link>
      <Separator size="nano" />
    </>
  )
}
const defaultBirthLikeObj = {
  details: { detailsType: 'EventDetails', sourceCount: 0, type: 'BIRTH' },
  type: 'BIRTH',
  multiValued: false,
} satisfies VitalEventConclusion
const defaultDeathLikeObj = {
  details: { detailsType: 'EventDetails', sourceCount: 0, type: 'DEATH' },
  type: 'DEATH',
  multiValued: false,
} satisfies VitalEventConclusion

function getBirthAndDeathLikeConclusions(
  displayPerson:
    | UnknownPerson
    | (SummaryPerson & Partial<TdPerson | CardPerson>)
    | LoadingPerson<Partial<TdPerson>>
    | undefined
): { birthLike: VitalEventConclusion; deathLike: VitalEventConclusion } {
  if (!displayPerson || isUnknownPerson(displayPerson)) {
    return { birthLike: defaultBirthLikeObj, deathLike: defaultDeathLikeObj }
  }

  const birthLike = displayPerson.birth ?? displayPerson.christening ?? defaultBirthLikeObj
  const deathLike =
    (displayPerson.death?.details.place || displayPerson.death?.details.date
      ? displayPerson.death
      : displayPerson.burial) ?? defaultDeathLikeObj

  return { birthLike, deathLike }
}

type PersonOverlaySheetSummaryProps = {
  cjk?: boolean
  displayPerson?: UnknownPerson | (SummaryPerson & Partial<TdPerson | CardPerson>) | LoadingPerson<Partial<TdPerson>>
  readOnlyMode?: boolean
  personHeadingRef?: MutableRefObject<HTMLDivElement | null> | null
  newTabProps?: Record<string, unknown>
  subheaderLink?: SubheaderLinkProps
  linksOpenNewTab?: boolean
  hideAssociated?: boolean
  showPQSTag?: boolean
}

function PersonOverlaySheetSummary({
  cjk: isCjk,
  displayPerson,
  readOnlyMode,
  personHeadingRef = null,
  newTabProps = {},
  subheaderLink,
  linksOpenNewTab,
  hideAssociated,
  showPQSTag,
}: PersonOverlaySheetSummaryProps): JSX.Element {
  const { insideRelationshipViewer } = useContext<{ insideRelationshipViewer: boolean }>(RelationshipViewerContext)
  const isSheet = Boolean(personHeadingRef)
  const backupRef = useRef<HTMLDivElement>(null)

  const [t] = useTranslation()

  const showAssociated =
    displayPerson?.treeId && 'mePersonCisId' in displayPerson && displayPerson.mePersonCisId && !hideAssociated
  const loading = !displayPerson || isLoadingPerson(displayPerson)
  const [hasPermissions] = usePermission('CanAddPersonalDataPermission', 'FamilyTree')
  const isCountryBlocked = !hasPermissions
  const templeOrdinancesState = useTempleOrdinances(displayPerson?.id)

  const ref = useRef<HTMLDivElement>(null)

  // We use this because we show loading content after opening, we then want to focus after it's loaded.
  useAutoFocus({ isOpen: !loading, enabled: true, containerRef: ref })

  const { birthLike, deathLike } = getBirthAndDeathLikeConclusions(displayPerson)

  if (loading) {
    return (
      <>
        <VisuallyHidden aria-live="assertive">{t('common-ui:loading.ellipsis.label')}</VisuallyHidden>
        <Person loading orientation="landscape" componentSize="sm" />
        <ConclusionSkel />
        <SideSheetDivider />
        <Row>
          <Skeleton.Button growX />
          <Skeleton.Button growX />
        </Row>
      </>
    )
  }

  return (
    <>
      {!loading && (
        <>
          <div ref={ref}>
            {(isUnknownPerson(displayPerson) || displayPerson.deleted) && <Banners displayPerson={displayPerson} />}

            <VisuallyHidden aria-live="assertive">
              {t('person.person-sheet.more-info', { name: displayPerson.name?.trim() })}
            </VisuallyHidden>

            <Separator size="nano" />

            <div ref={personHeadingRef || backupRef}>
              <Person
                linksOpenNewTab={linksOpenNewTab}
                personObj={displayPerson}
                data-testid={`Person${isSheet ? 'Sheet' : 'Overlay'}Header`}
                cjk={isCjk}
                orientation="landscape"
                componentSize="sm"
                hideLifespan
                avatarPropsOverride={{ gray: displayPerson.deleted }}
              />
            </div>

            {showPQSTag && displayPerson?.id && (
              <>
                <Separator size="nano" />
                <QualityScoreLabel pid={displayPerson.id} />
                <Separator size="nano" />
              </>
            )}

            {!isUnknownPerson(displayPerson) && (
              <>
                {showAssociated && <AssociatedUser cisId={displayPerson.mePersonCisId} />}
                {subheaderLink && <SubheaderLink {...subheaderLink} />}
                <div style={{ fontSize: 12 }}>
                  <Row alignX="start">
                    <Link
                      to={`/tree/person/sources/${displayPerson.id}`}
                      external
                      data-testid="sources-count"
                      wayfinding
                      {...newTabProps}
                    >
                      {t('person.person-overlay.sources-link-with-count', { count: displayPerson.sourceCount })}
                    </Link>
                    {!isCountryBlocked && (
                      <Link
                        to={`/tree/person/memories/${displayPerson.id}`}
                        external
                        data-testid="memories-count"
                        wayfinding
                        {...newTabProps}
                      >
                        {t('person.person-overlay.memories-link-with-count', { count: displayPerson.memoryCount })}
                      </Link>
                    )}
                    <Link
                      to={`/tree/person/collaborate/${displayPerson.id}`}
                      external
                      data-testid="collaborate-count"
                      wayfinding
                      {...newTabProps}
                    >
                      {t('person.person-overlay.collaborate-link-with-count', {
                        count: displayPerson.collaborateCount,
                      })}
                    </Link>
                  </Row>
                </div>

                <Conclusion
                  simple
                  inline
                  disableOverlay
                  // TODO - we should have better types to avoid the need for this cast
                  person={displayPerson as CardPerson}
                  conclusion={birthLike}
                  readOnly={readOnlyMode}
                  truncate
                />

                {!displayPerson.living && (
                  <Conclusion
                    simple
                    inline
                    disableOverlay
                    // TODO - we should have better types to avoid the need for this cast
                    person={displayPerson as CardPerson}
                    conclusion={deathLike}
                    readOnly={readOnlyMode}
                    truncate
                  />
                )}

                {displayPerson.living && (
                  <>
                    <Separator size="nano" />
                    <Tag color="blue" text={t('person.person-overlay.vital-block.death-information-living')} />
                    <Separator size="nano" />
                  </>
                )}
              </>
            )}
          </div>

          {!isUnknownPerson(displayPerson) && (
            <>
              {!displayPerson.researcherTree && !displayPerson.deleted && !displayPerson.living && (
                <div data-testid="temple-status-block">
                  <TempleOrdinances
                    pid={displayPerson.id}
                    ordinances={templeOrdinancesState.data}
                    loading={templeOrdinancesState.loading}
                    error={Boolean(templeOrdinancesState.error)}
                  />
                </div>
              )}
              <Row guttersY="none">
                <Follow
                  personObj={displayPerson}
                  analyticsName={`person_${isSheet ? 'sheet' : 'overlay'}:clicked_follow`}
                  buttonProps={{ emphasis: 'medium' }}
                />
                {!insideRelationshipViewer && !displayPerson.researcherTree && (
                  <RelationshipViewerButton toId={displayPerson.id} data-testid="relationship-viewer-button" hideText />
                )}
                <div growX />
              </Row>

              <Separator size="nano" />
              <Divider marginY="none" />
              <Separator size="xs" />

              <Row>
                <Button
                  growX
                  data-testid="view-person-button"
                  linkName={`person_${isSheet ? 'sheet' : 'overlay'}_person_link`}
                  emphasis="medium"
                  to={`/tree/person/${displayPerson.id === 'UNKNOWN' ? '' : displayPerson.id}`}
                  external
                  Icon={PersonIcon}
                  fullWidth
                  {...newTabProps}
                >
                  {t('person.person-overlay.link-to-person-page-for-this-person-action')}
                </Button>
                <Button
                  growX
                  data-testid="view-tree-button"
                  linkName={`person_${isSheet ? 'sheet' : 'overlay'}_pedigree_link`}
                  to={`/tree/pedigree/${displayPerson.id === 'UNKNOWN' ? '' : displayPerson.id}`}
                  external
                  emphasis="medium"
                  Icon={TreePedigree}
                  fullWidth
                  {...newTabProps}
                >
                  {t('person.person-overlay.link-to-tree-for-this-person-action')}
                </Button>
              </Row>
            </>
          )}
        </>
      )}
    </>
  )
}

export default memo(PersonOverlaySheetSummary)
