import { useEffect, useRef, useState } from 'react'
import axiosUntyped from '@fs/zion-axios'
import { useFeatureFlag } from '@fs/zion-flags'
import type axiosTyped from '@fs/zion-tree-types/zion-axios'
import { type AxiosResponse } from '@fs/zion-tree-types/zion-axios'
import { type AsyncScore } from '../types/scores'

type PQSValue = {
  scoreFromProvider: AsyncScore | undefined
  loadingFromProvider: boolean | undefined
}

const axios = axiosUntyped as typeof axiosTyped

const getDelayRefetchMs = (latestData: AsyncScore): number => {
  if (!latestData.isValid && 'currentCalculationDurationMillis' in latestData) {
    if (latestData.currentCalculationDurationMillis < 1_000) {
      return 200
    }
    if (latestData.currentCalculationDurationMillis < 5_000) {
      return 1_000
    }
    if (latestData.currentCalculationDurationMillis < 10_000) {
      return 2_000
    }
  }

  return 0
}

function getQualityScore(pid: string, limitScope: boolean): Promise<AxiosResponse<AsyncScore>> {
  return axios.get<AsyncScore>(
    // TODO limitScore does not do anything right now but should work later on. currently it is limited on prod and beta but not in integration.
    `/service/tree/tree-data/quality/person/${pid}/scores${!limitScope ? '?limitScope=false' : ''}`
  )
}

// https://learn.microsoft.com/en-us/javascript/api/@azure/keyvault-certificates/requireatleastone?view=azure-node-latest
type RequireAtLeastOne<T> = {
  [K in keyof T]-?: Required<Pick<T, K>> & Partial<Pick<T, Exclude<keyof T, K>>>
}[keyof T]

type Props = RequireAtLeastOne<{ score: AsyncScore | undefined; pid: string }> & { loading?: boolean }

export default function useQualityScore({ score, pid, loading }: Props): PQSValue {
  const [scoreFromProvider, setScoreFromProvider] = useState<AsyncScore | undefined>(score)
  const [loadingFromProvider, setLoadingFromProvider] = useState(!!pid || loading)
  const limitScope = !useFeatureFlag('treeWeb_developerMode').isOn
  const idRef = useRef<NodeJS.Timeout>()

  useEffect(() => {
    let isCurrent = true
    const fetchScore = async (personId: string): Promise<void> => {
      setLoadingFromProvider(true)
      const { data } = await getQualityScore(personId, limitScope)
      const delay = getDelayRefetchMs(data)
      if (delay) {
        idRef.current = setTimeout(() => fetchScore(personId), delay)
      }
      if (
        !delay &&
        !data.isValid &&
        'currentCalculationDurationMillis' in data &&
        data.currentCalculationDurationMillis >= 10_000
      ) {
        //  Show "Not Available At This Time"
        data.visibility = 'FORBIDDEN'
      }
      if (isCurrent) {
        setScoreFromProvider(data)
        setLoadingFromProvider(false)
      }
    }
    if (pid) fetchScore(pid)

    return () => {
      isCurrent = false
      if (idRef.current) clearTimeout(idRef.current)
    }
  }, [limitScope, pid, score])

  useEffect(() => {
    setScoreFromProvider(score)
  }, [score])

  useEffect(() => {
    !pid && setLoadingFromProvider(Boolean(loading))
  }, [loading, pid])

  return { scoreFromProvider, loadingFromProvider }
}
