import { i18n } from '@fs/zion-locale'
import { trackLink } from '@fs/zion-analytics'
import { followPerson, unfollowPerson } from './followService'

/**
 * @description - Handles the user clicking the follow button.
 * @param {function} dispatch - The useReducer dispatch function
 * @param {bool} follow - Whether we are now following the person
 * @param {function} pid - The Person ID
 * @param {string} analyticsName - The analytics key to be sent with clicking the button.
 * @param {function} statusOverlay - statusOverlay function begat by `useStatusOverlay`, son of ZionUI
 * @param {bool} useActionWording - Replaces "Following" state with "Unfollow" action word.
 */
export default function toggleFollowingState(args) {
  const { addLabelFn, analyticsName, dispatch, isFollowing, pid, name, statusOverlay, useActionWording } = args
  trackLink({ link_name: analyticsName })
  if (isFollowing) {
    dispatch({ type: 'transitionToFollow' })
    return followPerson(pid)
      .then(({ status }) => {
        if (status === 201) {
          dispatch({ type: 'following', pid, useActionWording })
          showStatusOverlay(true, statusOverlay, pid, name, addLabelFn, (follow) =>
            toggleFollowingState({ ...args, isFollowing: typeof follow === 'boolean' ? follow : !isFollowing })
          )
        } else {
          dispatch({ type: 'unavailable' })
          showErrorStatusOverlay('unavailable', statusOverlay)
        }
      })
      .catch((err) => {
        if (err?.response?.status === 409 || err?.response?.status === 451) {
          dispatch({ type: 'tooMany' })
          showErrorStatusOverlay('tooMany', statusOverlay)
        } else {
          dispatch({ type: 'unavailable' })
          showErrorStatusOverlay('unavailable', statusOverlay)
        }
      })
  }

  dispatch({ type: 'transitionToUnfollow', useActionWording })
  return unfollowPerson(pid)
    .then(({ status }) => {
      if (status === 204) {
        dispatch({ type: 'notFollowing', pid })
        showStatusOverlay(false, statusOverlay, pid, name, addLabelFn, (follow) =>
          toggleFollowingState({ ...args, isFollowing: typeof follow === 'boolean' ? follow : !isFollowing })
        )
      } else {
        dispatch({ type: 'unavailable' })
        showErrorStatusOverlay('unavailable', statusOverlay)
      }
    })
    .catch(() => {
      dispatch({ type: 'unavailable' })
      showErrorStatusOverlay('unavailable', statusOverlay)
    })
}

export function showStatusOverlay(isFollowing, statusOverlay, pid, name, addLabelFn, callToggleFollowingState) {
  const addLabelLink = `/tree/following/?addLabelPid=${pid}`
  const displayName = name || i18n.t('unknown-name', '[Unknown Name]')
  statusOverlay({
    message: isFollowing
      ? i18n.t('following-person', 'You are now following {name}.', { name: displayName })
      : i18n.t('not-following-person', 'You are no longer following {name}.', { name: displayName }),
    transient: true,
    actionLabel: isFollowing ? i18n.t('button.add-label', 'Add Label') : i18n.t('action.undo', 'Undo'),
    actionCallback: isFollowing
      ? () => {
          trackLink({ link_name: 'follow:click-add-label' })
          if (addLabelFn) {
            addLabelFn()
          } else {
            typeof window !== 'undefined' && window.open(addLabelLink, '_blank')
          }
        }
      : () => {
          trackLink({ link_name: 'follow:click-undo' })
          callToggleFollowingState(true).then(() => {
            // Since this is from a StatusOverlay in a React Portal, its common parent with the consumer will be document.body
            document.body.dispatchEvent(new CustomEvent(`followed-${pid}`))
          })
        },
  })
}

export function showErrorStatusOverlay(error, statusOverlay) {
  const message =
    error === 'tooMany'
      ? i18n.t(
          'unavailable.allowed-exceeded.hover-text',
          'You have exceeded the number of persons you are allowed to follow. To follow this person you will need to unfollow someone from the following list.'
        )
      : i18n.t(
          'unavailable.service-failure',
          'Something went wrong with following this person. Please try again later.'
        )

  statusOverlay({
    message,
    transient: true,
    dismissable: true,
  })
}
