import React, { useEffect, useReducer, useState, useCallback } from 'react'
import { useTranslation } from 'react-i18next'
import { usePreference } from '@fs/zion-preferences'
import { SocialStar } from '@fs/zion-icon'
import { Button, IconButton, ListItem, useStatusOverlay } from '@fs/zion-ui'
import PropTypes from 'prop-types'
import { getFollowStatus } from './lib/followService'
import reducer from './lib/followReducer'
import toggleFollowingState from './lib/helpers'

/**
 * @description Follow displays the following status for a given PID--clicking toggles state between following/unfollowing. Previously known as `watch`.
 * @param {function} addLabelFn - Custom function to perform instead of function for "Add Label" button. Mainly for use on Following page.
 * @param {string} analyticsName - The analytics key to be sent with clicking the button.
 * @param {string} as - The element type to be used. Only accepts 'ListItem', defaults to 'Button'.
 * @param {string} buttonEmphasis - [deprecated] emphasis prop to apply to Button.
 * @param {string} buttonProps - Props to pass down to the Button/IconButton/ListItem.
 * @param {string} initialState - Used as initial state and forgoes the initial endpoint call to get the state.
 * @param {object} personObj - The object of the person to display following status for.
 * @param {string} showText - Whether to display descriptive text.
 * @param {string} textOnly - Displays only button text with no Icon. Ignores showText prop.
 * @param {bool} useActionWording - Replaces "Following" state with "Unfollow" action word.
 */
export default function Follow({
  addLabelFn,
  analyticsName,
  as,
  buttonEmphasis, // Deprecated - remove with bump to 6.0.0
  buttonProps,
  initialState,
  personObj,
  showText,
  textOnly,
  useActionWording,
}) {
  const showRomanName = usePreference('tree.showNamesInRomanScript')
  const name =
    (showRomanName &&
      (personObj.romanizedName ??
        personObj.nameConclusion?.details?.nameForms?.filter((nameForm) => nameForm.script === 'ROMAN')?.[0]
          ?.fullText)) ||
    personObj.name
  const pid = personObj.id || personObj.personId
  const [t] = useTranslation()
  const followedStatusOverlay = useStatusOverlay()
  const [stopEndpointCalls, setStopEndpointCalls] = useState(['following', 'notFollowing'].includes(initialState))
  const [state, dispatch] = useReducer(reducer, { initialLoad: true })
  const dataTestId = `${state.isFollowing ? 'Following' : 'Follow'}_${pid}`

  // TODO: Remove this code block when deprecating `buttonEmphasis`
  if (buttonEmphasis && !buttonProps.emphasis) {
    buttonProps.emphasis = buttonEmphasis
  }

  useEffect(() => {
    if (stopEndpointCalls) {
      dispatch({ type: initialState, useActionWording })
      setStopEndpointCalls(false)
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps -- We only want this running on its first render.
  }, [])

  useEffect(() => {
    let isCurrent = true
    if (!stopEndpointCalls && !!pid) {
      getFollowStatus(pid)
        .then(({ data }) => {
          if (isCurrent) {
            if (data?.followable && data?.following) dispatch({ type: 'following', useActionWording })
            else if (data?.followable && !data?.following) dispatch({ type: 'notFollowing' })
            else if (!data?.followable) dispatch({ type: 'notFollowable' })
            else dispatch({ type: 'unavailable' })
          }
        })
        .catch(() => {
          if (isCurrent) dispatch({ type: 'unavailable' })
        })
    }
    return () => {
      isCurrent = false
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps -- We don't want this to trigger on changes to `stopEndpointCalls`.
  }, [pid, t, useActionWording])

  const callToggleFollowing = useCallback(
    (follow) =>
      toggleFollowingState({
        addLabelFn,
        analyticsName,
        dispatch,
        statusOverlay: followedStatusOverlay,
        // isFollowing could come in as an event object. Only use it if it's a boolean
        isFollowing: typeof follow === 'boolean' ? follow : !state.isFollowing,
        name,
        pid,
        useActionWording,
      }),
    [addLabelFn, analyticsName, followedStatusOverlay, name, pid, state.isFollowing, useActionWording]
  )

  // this must be a stable-ish function in order for click events to fire when it is used within a ZoomPan
  const StatefulSocialStar = useCallback(() => {
    return <SocialStar toggle={state.isFollowing} />
  }, [state.isFollowing])
  const IconToUse = state.Icon ?? StatefulSocialStar

  // Don't show Follow button until first endpoint call has been made
  if (state.initialLoad) return null

  // Don't show Follow component if person is set to not followable, unless the call to determine "followableness" failed and it is disabled, then we let it through to show "Unavailable"
  if ((!state.disabled && !state.followable) || personObj.unknown) return null

  const elementProps = {
    ...buttonProps,
    'aria-label': state.hoverText,
    'data-testid': dataTestId,
    disabled: state.disabled,
    title: state.hoverText,
    onClick: callToggleFollowing,
  }

  if (as === 'ListItem') {
    return <ListItem {...elementProps} primaryText={state.buttonText ?? ''} />
  }

  return (
    <>
      {showText || textOnly ? (
        <Button {...elementProps} Icon={!textOnly ? SocialStar : null} iconToggle={state.isFollowing}>
          {state.buttonText}
        </Button>
      ) : (
        <IconButton {...elementProps} Icon={IconToUse} />
      )}
    </>
  )
}
Follow.propTypes = {
  /** Custom function to perform instead of function for "Add Label" button. Mainly for use on Following page. */
  addLabelFn: PropTypes.func,
  /** The analytics key to be sent with clicking the button. */
  analyticsName: PropTypes.string,
  /** Render as something else. Useful for rendering in Lists as ListItem. */
  as: PropTypes.string,
  /** [deprecated] emphasis prop to apply to Button. */
  buttonEmphasis: PropTypes.string,
  /** Props to pass down to the Button/IconButton/ListItem. Setting emphasis to 'medium' will show IconButton as blue. */
  buttonProps: PropTypes.shape({
    dense: PropTypes.bool,
    emphasis: PropTypes.string,
  }),
  /** Used as initial state and forgoes the initial endpoint call to get the state. */
  initialState: PropTypes.oneOf(['following', 'notFollowing']),
  /** A Tree Person object. */
  personObj: PropTypes.shape({
    /** The ID of the person to display following status for. Synonymous with personId. */
    id: PropTypes.string,
    /** The ID of the person to display following status for. Synonymous with id. */
    personId: PropTypes.string,
    /** The name of the person to display in the statusOverlay. */
    name: PropTypes.string.isRequired,
    /** Is the person deleted? */
    deleted: PropTypes.bool,
    /** Is the person in the private space (usually a restricted country name or living)? */
    visibleToAll: PropTypes.bool,
    /** Is the person living (if this is true, inPrivateSpace is also likely true)? */
    living: PropTypes.bool,
    /** Is the person unknown (set if we couldn't get a person)? */
    unknown: PropTypes.bool,
  }).isRequired,
  showText: PropTypes.bool,
  /** Displays only button text with no Icon. Ignores showText prop. */
  textOnly: PropTypes.bool,
  /** Whether to replace state wording (Following) with action wording (Unfollow). */
  useActionWording: PropTypes.bool,
}
Follow.defaultProps = {
  analyticsName: 'clicked_follow',
  as: 'Button',
  buttonEmphasis: 'low',
  buttonProps: {},
  initialState: null,
  showText: false,
  textOnly: false,
  useActionWording: false,
}
