export function isUnknownPerson<T>(person: T): person is Extract<T, { unknown: true }> {
  return Boolean(person && typeof person === 'object' && 'unknown' in person && person.unknown === true)
}

export function isLoadingPerson<T>(person: T): person is Extract<T, { loading: true }> {
  return Boolean(person && typeof person === 'object' && 'loading' in person && person.loading === true)
}

export function isUnavailablePerson<T>(person: T): person is Extract<T, { unavailablePerson: true }> {
  return Boolean(
    person && typeof person === 'object' && 'unavailablePerson' in person && person.unavailablePerson === true
  )
}
